=Generate a complete Change Request document for the following requirement:

{{ $json.changeRequest }}

Respond with a JSON object only.

parameters.jsCode:
const raw = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || $input.first().json.text || '';

let parsed;
try {
  const clean = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  // Fallback: try to extract sections from plain text
  const sections = [
    'shortDescription', 'changeDescription', 'impactDuringImpl',
    'impactIfNotExecuted', 'worstCaseScenario', 'changeJustification',
    'implementationPlan', 'backoutPlan', 'testPlan'
  ];
  const headers = {
    shortDescription: 'Short Description',
    changeDescription: 'Change Description',
    impactDuringImpl: 'Impact during implementation',
    impactIfNotExecuted: 'Impact \\(if not executed\\)',
    worstCaseScenario: 'Worst Case Scenario',
    changeJustification: 'Change Justification',
    implementationPlan: 'Implementation plan',
    backoutPlan: 'Backout Plan',
    testPlan: 'Test Plan'
  };
  parsed = {};
  sections.forEach(key => {
    const h = headers[key];
    const regex = new RegExp(`${h}\\s*[:\\-]?\\s*([\\s\\S]*?)(?=\n[A-Z]|$)`, 'i');
    const match = raw.match(regex);
    parsed[key] = match ? match[1].trim() : 'Not available';
  });
}

return [{ json: { ...parsed, _rawResponse: raw, _success: true } }];
